// ────────────────────────────────────────────────
// 3) getFontSize (v7 글자 자동 스케일)
// ────────────────────────────────────────────────
// 강조 마크업(**...**) 제거 후 실제 글자수만 계산
const stripMarkup = (text) => typeof text === 'string' ? text.replace(/\*\*([^*]+)\*\*/g, '$1') : '';

const getHeadSize = (text, kind, base = 28) => {
  if (!text) return base;
  const clean = stripMarkup(String(text));
  const lines = clean.split('\n');
  const maxLine = Math.max(...lines.map(l => l.length));
  const lineCount = lines.length;

  if (kind === 'hook' || kind === 'titleSlide') {
    // 인스타 하단 UI 침범 방지 — 줄 많을수록 강하게 축소
    if (lineCount >= 5) return 18;
    if (lineCount >= 4) return 21;
    if (lineCount >= 3) {
      if (maxLine <= 6) return 28;
      if (maxLine <= 10) return 24;
      return 20;
    }
    // 1-2줄
    if (maxLine <= 5) return 40;
    if (maxLine <= 8) return 34;
    if (maxLine <= 12) return 28;
    if (maxLine <= 16) return 23;
    return 19;
  }
  if (kind === 'cta') {
    if (lineCount >= 4) return 16;
    if (maxLine <= 8) return 22;
    if (maxLine <= 12) return 19;
    return 17;
  }
  // 일반 (checkItem, card 등) — 안전영역 보호 강화
  if (lineCount >= 5) return 14;
  if (lineCount >= 4) return 16;
  if (lineCount >= 3) {
    if (maxLine <= 8) return 22;
    if (maxLine <= 14) return 19;
    return 16;
  }
  // 1-2줄
  if (maxLine <= 5) return 30;
  if (maxLine <= 8) return 26;
  if (maxLine <= 12) return 22;
  if (maxLine <= 16) return 19;
  return 16;
};

const getSubSize = (text, kind) => {
  if (!text) return 13;
  const clean = stripMarkup(String(text));
  const lines = clean.split('\n');
  const lineCount = lines.length;
  const totalLen = clean.length;
  if (kind === 'cta') return totalLen > 50 ? 11 : 12;
  if (lineCount >= 4) return 10.5;
  if (lineCount >= 3) return 11.5;
  if (totalLen > 70) return 11;
  if (totalLen > 50) return 12;
  return 13;
};

const getBigNumberSize = (text) => {
  if (!text) return 110;
  const s = stripMarkup(String(text));
  if (s.length <= 2) return 130;
  if (s.length <= 3) return 110;
  if (s.length <= 4) return 90;
  return 72;
};

