// 헬퍼: 디자인 언어 + 색 테마 합치기
function applyLayoutLanguage(theme, layoutKey) {
  const rawLang = LAYOUT_LANGUAGES[layoutKey] || LAYOUT_LANGUAGES.editorial;
  // id 필드가 없으면 자동 주입 (LAYOUT 정의에 id 빠져도 동작 보장)
  const lang = rawLang.id ? rawLang : { ...rawLang, id: LAYOUT_LANGUAGES[layoutKey] ? layoutKey : 'editorial' };
  // 기존 theme 위에 lang 적용
  return {
    ...theme,
    _layout: lang,                       // 디자인 언어 토큰 통째로 저장
    layout: lang.align,                  // 기존 layout 필드와 호환
    // radius는 디자인 언어가 결정
    radius: {
      sm: lang.cardRadius,
      md: lang.cardRadius,
      lg: lang.cardRadius * 1.5,
    },
  };
}

// ────────────────────────────────────────────────
// 3-A.6) 디자인 언어 → 슬라이드 스타일 자동 적용 헬퍼
//   각 슬라이드가 theme._layout 토큰을 자동 반영하도록.
//   기존 분기(layoutId === 'xxx')는 그대로 두고, 폴백 경로에서 이걸 호출.
// ────────────────────────────────────────────────
function getLayoutStyles(theme, base, opts = {}) {
  const lang = theme._layout || LAYOUT_LANGUAGES.editorial;
  const {
    baseHeadSize = 36,
    baseSubSize  = 16,
    basePadding  = 32,
  } = opts;

  const align = lang.align === 'leftAlign' ? 'left' : 'center';
  const items = lang.align === 'leftAlign' ? 'flex-start' : 'center';
  const padMult = lang.paddingMultiplier ?? 1;

  return {
    align,                                                // 'left' | 'center'
    items,                                                // flex alignItems 값
    headSize: Math.round(baseHeadSize * (lang.headSizeMultiplier ?? 1)),
    subSize:  Math.round(baseSubSize  * (lang.subSizeMultiplier  ?? 1)),
    headWeight: lang.headFontWeight ?? theme.fontWeight?.bold ?? 800,
    subWeight:  lang.subFontWeight  ?? theme.fontWeight?.regular ?? 500,
    headLetter: lang.headLetterSpacing ?? '-0.02em',
    subLetter:  lang.subLetterSpacing  ?? '0',
    padding:    Math.round(basePadding * padMult),
    cardRadius: lang.cardRadius ?? 16,
    sceneBorder: lang.sceneBorder === 'thick'
      ? `3px solid ${theme.text}`
      : lang.sceneBorder === 'thin'
        ? `1px solid ${theme.primarySoft}`
        : 'none',
    chapterMark: !!lang.chapterMark,
    bgPattern: lang.bgPattern || 'none',
    // 컨테이너에 그대로 spread 할 수 있는 스타일
    container: {
      ...base,
      textAlign: align,
      alignItems: items,
      padding: Math.round(basePadding * padMult),
      border: lang.sceneBorder === 'thick'
        ? `3px solid ${theme.text}`
        : lang.sceneBorder === 'thin'
          ? `1px solid ${theme.primarySoft}`
          : undefined,
    },
  };
}

// 배경 패턴 (디자인 언어별 데코) — 가벼운 SVG/Div 데코를 슬라이드 뒤에 까는 헬퍼
function LayoutBgDecor({ theme }) {
  const lang = theme._layout || LAYOUT_LANGUAGES.editorial;
  const pat = lang.bgPattern;
  if (!pat || pat === 'none') return null;
  const tint = theme.primarySoft || '#eee';
  const tintMute = theme.textMute  || '#bbb';

  if (pat === 'dots') {
    return (
      <div aria-hidden style={{
        position:'absolute', inset:0, zIndex:0, opacity:0.35,
        backgroundImage: `radial-gradient(${tintMute} 1px, transparent 1px)`,
        backgroundSize: '14px 14px', pointerEvents:'none',
      }}/>
    );
  }
  if (pat === 'gridLines') {
    return (
      <div aria-hidden style={{
        position:'absolute', inset:0, zIndex:0, opacity:0.18,
        backgroundImage: `linear-gradient(${tintMute} 1px, transparent 1px), linear-gradient(90deg, ${tintMute} 1px, transparent 1px)`,
        backgroundSize: '24px 24px', pointerEvents:'none',
      }}/>
    );
  }
  if (pat === 'curves') {
    return (
      <svg aria-hidden style={{ position:'absolute', inset:0, zIndex:0, width:'100%', height:'100%', opacity:0.35, pointerEvents:'none' }} preserveAspectRatio="none" viewBox="0 0 400 700">
        <path d="M -50 580 Q 200 480 450 600" stroke={tint} strokeWidth="60" fill="none" strokeLinecap="round" opacity="0.6"/>
        <path d="M -50 100 Q 150 60  400 130" stroke={tint} strokeWidth="40" fill="none" strokeLinecap="round" opacity="0.45"/>
      </svg>
    );
  }
  if (pat === 'editorial') {
    return (
      <div aria-hidden style={{
        position:'absolute', left:24, right:24, top:24, height:1,
        background: theme.text, opacity:0.85, zIndex:0, pointerEvents:'none',
      }}/>
    );
  }
  if (pat === 'columnLine') {
    return (
      <div aria-hidden style={{
        position:'absolute', top:0, bottom:0, left:'50%', width:1,
        background: theme.text, opacity:0.25, zIndex:0, pointerEvents:'none',
      }}/>
    );
  }
  if (pat === 'softWatermark') {
    return (
      <div aria-hidden style={{
        position:'absolute', right:-30, bottom:-30, fontSize:180,
        fontWeight:900, color:tint, opacity:0.25, lineHeight:1, zIndex:0,
        letterSpacing:'-0.04em', pointerEvents:'none',
      }}>ABA</div>
    );
  }
  if (pat === 'solidBlock') {
    return (
      <div aria-hidden style={{
        position:'absolute', left:0, right:0, top:0, height:'45%',
        background: theme.primary, opacity:0.18, zIndex:0, pointerEvents:'none',
      }}/>
    );
  }
  return null;
}

// 챕터 마크 (좌상단) — 일부 디자인 언어에서만 표시
function ChapterMark({ scene, theme }) {
  const lang = theme._layout || LAYOUT_LANGUAGES.editorial;
  if (!lang.chapterMark) return null;
  if (!scene.index || !scene.total) return null;
  return (
    <div style={{
      position:'absolute', left:20, top:18, zIndex:2,
      fontSize: 10, letterSpacing:'0.15em', fontWeight: 700,
      color: theme.textMute,
    }}>
      {String(scene.index).padStart(2,'0')} / {String(scene.total).padStart(2,'0')}
    </div>
  );
}

