// API 에러를 사용자 친화적 메시지로 변환
const friendlyApiError = (status, errText = '') => {
  const errLower = (errText || '').toLowerCase();
  if (status === 401 || status === 403) return '인증 오류예요. 잠시 후 다시 시도해주세요.';
  if (status === 429) return '잠시 요청이 많아요. 1-2분 뒤 다시 시도해주세요.';
  if (status === 500 || status === 502 || status === 503) return 'AI 서버가 잠시 불안정해요. 잠시 후 다시 시도해주세요.';
  if (status === 400) {
    // 토큰 길이 초과
    if (errLower.includes('max_tokens') || errLower.includes('token') || errLower.includes('length') || errLower.includes('context')) {
      return '응답이 너무 길어요. 주제를 짧게 줄여서 다시 시도해주세요.';
    }
    // 콘텐츠 정책
    if (errLower.includes('content') || errLower.includes('policy') || errLower.includes('filter') || errLower.includes('safety')) {
      return '콘텐츠 정책으로 거부됐어요. 다른 주제로 시도해주세요.';
    }
    // 그 외 — errText 일부 보여주기 (디버깅용)
    const snippet = (errText || '').slice(0, 80);
    return snippet
      ? `요청 오류: ${snippet}... 다시 시도하거나 주제를 바꿔보세요.`
      : '요청에 일시적 문제가 있었어요. 다시 한 번 [AI로 자동 채우기] 눌러주세요.';
  }
  return `오류가 발생했어요 (${status}). 잠시 후 다시 시도해주세요.`;
};

const friendlyNetworkError = (err) => {
  const msg = err?.message || '';
  const lower = msg.toLowerCase();

  // 네트워크 연결 문제
  if (lower.includes('failed to fetch') || lower.includes('networkerror') || lower.includes('network request failed')) {
    return '인터넷 연결이 끊겼어요. 와이파이/데이터 확인하고 다시 시도해주세요.';
  }
  if (lower.includes('timeout') || lower.includes('timed out')) {
    return '응답이 너무 늦어요 (서버가 바쁘거나 인터넷이 느려요). 잠시 후 다시 시도해주세요.';
  }

  // API 응답 상태 코드 기반
  if (msg.includes('429') || lower.includes('rate limit') || lower.includes('too many')) {
    return '요청이 너무 많아요. 30초~1분 정도 기다렸다가 다시 시도해주세요.';
  }
  if (msg.includes('401') || lower.includes('unauthorized') || lower.includes('authentication')) {
    return '인증 문제가 생겼어요. 페이지를 새로고침해주세요.';
  }
  if (msg.includes('402') || lower.includes('insufficient') || lower.includes('credit') || lower.includes('quota')) {
    return 'API 사용량이 한도에 도달했어요. 잠시 후 다시 시도해주세요.';
  }
  if (msg.includes('403') || lower.includes('forbidden')) {
    return '요청이 거부됐어요. 콘텐츠 정책에 맞지 않을 수 있어요. 다른 주제로 시도해주세요.';
  }
  if (msg.includes('500') || msg.includes('502') || msg.includes('503') || msg.includes('504') || lower.includes('internal server')) {
    return '서버가 일시적으로 응답을 못 해요. 1~2분 뒤 다시 시도해주세요.';
  }
  if (msg.includes('400') || lower.includes('bad request') || lower.includes('invalid')) {
    return '요청에 문제가 있었어요. 주제를 좀 더 명확하게 적어보고 다시 시도해주세요.';
  }

  // JSON 파싱 실패
  if (lower.includes('json') && (lower.includes('parse') || lower.includes('파싱'))) {
    return 'AI 응답이 중간에 잘렸어요. 길이를 짧게(20초) 선택하거나 주제를 더 간결하게 적어보세요.';
  }

  // 그 외
  return msg || '알 수 없는 오류가 발생했어요. 다시 시도해주세요.';
};

// ────────────────────────────────────────────────
// 모바일 감지 (artifact wrapper의 fetch 제약 회피)
// ────────────────────────────────────────────────
const isMobileDevice = () => {
  if (typeof navigator === 'undefined') return false;
  const ua = navigator.userAgent || '';
  return /Mobi|Android|iPhone|iPad|iPod/i.test(ua);
};

// ────────────────────────────────────────────────
// LLM 호출 헬퍼 — Anthropic API 직접 호출
// 주의: 모바일 Claude 앱/iOS Safari에서는 artifact wrapper 제약으로 동작 안 함.
// PC 브라우저 (크롬/엣지/사파리)에서만 안정적으로 동작.
// ────────────────────────────────────────────────
const callLLM = async (prompt) => {
  const _isMobile = isMobileDevice();
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), _isMobile ? 60000 : 90000);
  let response;
  try {
    response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: _isMobile ? 2500 : 3500,
        messages: [{ role: 'user', content: prompt }],
      }),
      signal: controller.signal,
    });
  } finally {
    clearTimeout(timeoutId);
  }
  if (!response.ok) {
    let errText = '';
    try { errText = await response.text(); } catch {}
    throw new Error(`HTTP ${response.status}: ${errText.slice(0, 200)}`);
  }
  const data = await response.json();
  if (!data || !Array.isArray(data.content)) {
    throw new Error(`응답구조 이상: keys=${Object.keys(data || {}).join(',')}`);
  }
  const text = data.content.map(b => b.type === 'text' ? b.text : '').filter(Boolean).join('\n').trim();
  if (!text) throw new Error('빈 응답');
  return text;
};

const ICON_CATEGORIES = ['임상', '시간', '아이', '부모', '데이터', '일반'];

// ────────────────────────────────────────────────
// 텍스트 강조 (**단어**) 파서 — 테마 컬러 + 굵게
// ────────────────────────────────────────────────
const renderEmphasis = (text, accentColor, mode = 'color') => {
  if (typeof text !== 'string') return text;
  // 강조도 없고 줄바꿈도 없으면 그대로
  if (!text.includes('**') && !text.includes('\n')) return text;

  const parts = text.split(/(\*\*[^*]+\*\*)/g);
  return parts.map((part, i) => {
    const m = part.match(/^\*\*(.+)\*\*$/);
    if (m) {
      // 강조 부분 — 'highlight' 모드면 노란 형광펜 배경, 아니면 색상+굵기 800
      const emphasisStyle = mode === 'highlight'
        ? {
            background: `linear-gradient(180deg, transparent 55%, ${accentColor || '#FFF59D'} 55%, ${accentColor || '#FFF59D'} 92%, transparent 92%)`,
            color: '#1a1a1a',
            fontWeight: 800,
            padding: '0 2px',
          }
        : { color: accentColor || PKD, fontWeight: 800 };
      return (
        <span key={i} style={emphasisStyle}>
          {m[1].split('\n').map((line, j, arr) => (
            <React.Fragment key={j}>
              {line}
              {j < arr.length - 1 && <br/>}
            </React.Fragment>
          ))}
        </span>
      );
    }
    // 일반 텍스트 — \n을 <br/>로
    if (part.includes('\n')) {
      return part.split('\n').map((line, j, arr) => (
        <React.Fragment key={`${i}-${j}`}>
          {line}
          {j < arr.length - 1 && <br/>}
        </React.Fragment>
      ));
    }
    return part;
  });
};

// 강조 마크업 제거 (글자수 계산용)
const stripEmphasis = (text) => {
  if (typeof text !== 'string') return text;
  return text.replace(/\*\*([^*]+)\*\*/g, '$1');
};

// ────────────────────────────────────────────────
// 폰트 사이즈 자동 계산 (글자수 + 줄바꿈 + 안전영역)
// 인스타 릴스 하단 UI는 화면 25% 차지 — 텍스트가 거기 침범 안 하게
// ────────────────────────────────────────────────
const computeFontSize = (text, opts = {}) => {
  const {
    maxSize = 32,      // 한 줄 짧을 때 최대
    minSize = 14,      // 길거나 줄 많을 때 최소
    charWidth = 12,    // 글자당 추정 가로 px (한글 기준)
    maxLines = 4,      // 안전영역 내 최대 줄 수
    containerWidth = 320, // 슬라이드 너비 추정 (9:16 비율 px)
  } = opts;
  if (!text) return maxSize;

  const stripped = stripEmphasis(String(text));
  const lines = stripped.split('\n');
  const lineCount = lines.length;
  const longestLine = Math.max(...lines.map(l => l.length));

  // 줄바꿈이 많을수록 폰트 작게 (선형 보간)
  let size = maxSize;
  if (lineCount > 1) {
    const reduction = (lineCount - 1) * 4;
    size = Math.max(minSize, maxSize - reduction);
  }

  // 가로로 안 넘치는지 체크
  const maxByWidth = Math.floor(containerWidth / Math.max(longestLine, 1));
  size = Math.min(size, maxByWidth);

  // 안전 영역 침범 방지 — 줄이 maxLines 초과면 더 줄임
  if (lineCount > maxLines) {
    size = Math.max(minSize, size - (lineCount - maxLines) * 3);
  }

  return Math.max(minSize, Math.min(maxSize, size));
};

// 아이콘 컴포넌트
const Icon = ({ name, size = 24, color, strokeWidth = 1.8, style, colorful = false }) => {
  // 컬러풀 모드: 멀티컬러 SVG 사용
  if (colorful && COLORFUL_ICONS[name]) {
    return COLORFUL_ICONS[name]({ size, style });
  }
  // 일반 라인 모드
  const icon = ICON_SET[name];
  if (!icon) return null;
  return (
    <svg width={size} height={size} viewBox="0 0 24 24"
      fill="none" stroke={color || 'currentColor'}
      strokeWidth={strokeWidth} strokeLinecap="round" strokeLinejoin="round"
      style={style}
    >
      {icon.paths.map((d, i) => <path key={i} d={d}/>)}
    </svg>
  );
};

