// 4) 임상가 지속 성장 사이클 — 학습 → 실천 → 피드백 → 성찰
const ProfessionalGrowth = ({ tone, data }) => {
  const stages = [
    { label: '학습', sub: '새 지식·기법', pos: 'top'    },
    { label: '실천', sub: '회기 적용',    pos: 'right'  },
    { label: '피드백', sub: '슈퍼비전',   pos: 'bottom' },
    { label: '성찰', sub: '경험 정리',    pos: 'left'   },
  ];
  const cx = 150, cy = 62;
  const centerR = 13;
  const stepR = 11;
  const orbitX = 56, orbitY = 30;
  return (
    <svg viewBox="0 0 300 130" style={{ width:'100%', height:'auto' }}>
      <text x={150} y={11} textAnchor="middle" fontSize="9" fontFamily="Pretendard" fill={tone.accentDeep} fontWeight="600" letterSpacing="2">
        임상가의 지속 성장
      </text>
      {(() => {
        const positions = [
          { x: cx,           y: cy - orbitY, subX: cx,           subY: cy - orbitY - stepR - 2, anchor: 'middle' },
          { x: cx + orbitX,  y: cy,          subX: cx + orbitX + stepR + 4, subY: cy + 2,             anchor: 'start'  },
          { x: cx,           y: cy + orbitY, subX: cx,           subY: cy + orbitY + stepR + 8, anchor: 'middle' },
          { x: cx - orbitX,  y: cy,          subX: cx - orbitX - stepR - 4, subY: cy + 2,             anchor: 'end'    },
        ];
        return (
          <>
            {positions.map((p, i) => {
              const next = positions[(i + 1) % 4];
              return (
                <path key={`a${i}`}
                  d={`M ${p.x} ${p.y} Q ${cx} ${cy} ${next.x} ${next.y}`}
                  fill="none" stroke={tone.line} strokeWidth="0.7" strokeDasharray="2 2"/>
              );
            })}
            <circle cx={cx} cy={cy} r={centerR} fill={tone.accentDeep} opacity="0.95"/>
            <text x={cx} y={cy-1} textAnchor="middle" fontSize="6.5" fontWeight="900" fill="#fff">GROW</text>
            <text x={cx} y={cy+7} textAnchor="middle" fontSize="5.5" fontWeight="700" fill="#fff">CYCLE</text>
            {positions.map((p, i) => (
              <g key={`s${i}`}>
                <circle cx={p.x} cy={p.y} r={stepR} fill={tone.soft} stroke={tone.accentDeep} strokeWidth="0.8"/>
                <text x={p.x} y={p.y+3} textAnchor="middle" fontSize="8" fontWeight="800" fill={tone.accentDeep}>{stages[i].label}</text>
                <text x={p.subX} y={p.subY} textAnchor={p.anchor} fontSize="6.5" fill={INK_MUTE}>{stages[i].sub}</text>
              </g>
            ))}
          </>
        );
      })()}
      <text x={150} y={122} textAnchor="middle" fontSize="7" fill={INK_MUTE} letterSpacing="1">
        Continuous Professional Growth
      </text>
    </svg>
  );
};

