// 9) 첫 단어들 — 사람 빼고 말풍선만 (어휘 폭발)
const WordBubbleScene = ({ tone, data }) => {
  // 말풍선 5개를 다양한 크기·각도로 흩뿌리기
  const bubbles = [
    { x: 60,  y: 38, rx: 24, ry: 12, word: '"엄 마"', fs: 9,  rot: -5 },
    { x: 130, y: 28, rx: 18, ry: 10, word: '"물"',    fs: 11, rot: 4 },
    { x: 200, y: 26, rx: 18, ry: 10, word: '"또"',    fs: 11, rot: -3 },
    { x: 90,  y: 78, rx: 22, ry: 12, word: '"좋아"', fs: 9,  rot: 6 },
    { x: 175, y: 75, rx: 22, ry: 12, word: '"줘 요"', fs: 9, rot: -4 },
    { x: 245, y: 65, rx: 20, ry: 11, word: '"안 녕"',  fs: 8, rot: 8 },
  ];
  return (
    <svg viewBox="0 0 300 130" style={{ width:'100%', height:'auto' }}>
      <text x={150} y={11} textAnchor="middle" fontSize="9" fontFamily="Pretendard" fill={tone.accentDeep} fontWeight="600" letterSpacing="2">
        한 단어, 한 단어
      </text>
      {/* 말풍선 6개 (각도·크기·색상 다양) */}
      {bubbles.map((b, i) => (
        <g key={i} transform={`rotate(${b.rot} ${b.x} ${b.y})`}>
          <ellipse cx={b.x} cy={b.y} rx={b.rx} ry={b.ry}
            fill={i % 2 === 0 ? tone.accent : tone.soft}
            opacity={0.85}
            stroke={tone.accentDeep} strokeWidth="0.8"/>
          {/* 말풍선 꼬리 (랜덤 방향) */}
          <path d={`M ${b.x - b.rx*0.3} ${b.y + b.ry*0.7} L ${b.x - b.rx*0.5} ${b.y + b.ry*1.4} L ${b.x - b.rx*0.1} ${b.y + b.ry*0.9} Z`}
            fill={i % 2 === 0 ? tone.accent : tone.soft}
            stroke={tone.accentDeep} strokeWidth="0.8"/>
          <text x={b.x} y={b.y + 3} textAnchor="middle" fontSize={b.fs} fontWeight="900" fill={tone.accentDeep}>{b.word}</text>
        </g>
      ))}
      {/* 가운데 ★ 강조 */}
      <text x={150} y={56} textAnchor="middle" fontSize="11" fontWeight="900" fill={tone.accentDeep} opacity="0.6">+</text>
      <text x={150} y={120} textAnchor="middle" fontSize="6.5" fill={INK_MUTE} letterSpacing="1">
        Vocabulary Burst
      </text>
    </svg>
  );
};

